import { useEffect, useMemo, useRef, useState } from '@wordpress/element';
import { __ } from '@wordpress/i18n';
// @ts-ignore — @wordpress/api-fetch ships with WordPress.
import apiFetch from '@wordpress/api-fetch';

type EditProps = {
    data: Record< string, any >;
    field: Record< string, any >;
    onChange: ( next: Record< string, any > ) => void;
};

const RELOAD_SENTINEL_KEY = 'dokan-rank-math-just-reloaded-for';

const getLocalizedObjectId = (): number => {
    const config = ( window as any ).rankMath;
    return Number( config?.objectID ) || 0;
};

const consumeReloadSentinel = (): number => {
    try {
        const raw = sessionStorage.getItem( RELOAD_SENTINEL_KEY );
        sessionStorage.removeItem( RELOAD_SENTINEL_KEY );
        return Number( raw ) || 0;
    } catch ( e ) {
        return 0;
    }
};

// Edit component for the `rank_math_seo` variant.
//
// Why the reload dance: Rank Math's editor bundle reads the post it should
// operate on from `PostScreen::get_object_id()`, which inspects the request
// (`$_GET['product_id']`) or the `dokan_rank_math_edit_post_id` user meta.
// On the new editor the product id lives in the URL hash so the server
// can't see it, and on the very first visit the meta is missing too. The
// localized `rankMath.objectID` becomes 0, so canonical URL, snippet
// preview, schema type, social meta, and the SEO analysis all reflect an
// unrelated/empty post.
//
// To match legacy behavior we POST the product id into the user meta and
// reload exactly once per product id. After the reload, PostScreen returns
// the correct id, so Rank Math localizes the right data and every panel —
// preview snippet, advanced, schema (WooCommerce Product), social tab —
// behaves identically to the legacy product editor.
const RankMathMount = ( { data }: EditProps ) => {
    const productId = Number( data?.id ) || 0;
    const isNew = productId === 0;
    const mountedRef = useRef( false );

    const [ reloadedFor ] = useState( consumeReloadSentinel );

    const needsSync = useMemo( () => {
        if ( isNew || ! productId ) {
            return false;
        }
        if ( reloadedFor === productId ) {
            return false;
        }
        return getLocalizedObjectId() !== productId;
    }, [ isNew, productId, reloadedFor ] );

    useEffect( () => {
        if ( ! needsSync ) {
            return;
        }

        try {
            sessionStorage.setItem( RELOAD_SENTINEL_KEY, String( productId ) );
        } catch ( e ) {
            // Swallow — quota/private mode shouldn't block the reload.
        }

        apiFetch( {
            path: `/dokan/v2/rank-math/${ productId }/store-current-editable-post`,
            method: 'POST',
        } )
            .catch( () => {} )
            .finally( () => {
                window.location.reload();
            } );
    }, [ needsSync, productId ] );

    useEffect( () => {
        if ( isNew || ! productId || needsSync ) {
            return;
        }

        // Re-check the wrapper on every new product id to handle SPA
        // navigation between two saved products.
        mountedRef.current = false;

        // Rank Math's classic.js schedules its first mount with
        // `setTimeout(mount, 1000)`. On the new dashboard the product
        // editor often finishes rendering after that 1s window, leaving
        // the wrapper empty. Re-run the same mount sequence ourselves.
        const tryMount = () => {
            if ( mountedRef.current ) {
                return true;
            }
            const wrapper = document.getElementById(
                'rank-math-metabox-wrapper'
            );
            if ( ! wrapper ) {
                return false;
            }
            if ( wrapper.childElementCount > 0 ) {
                mountedRef.current = true;
                return true;
            }
            const wp = ( window as any ).wp;
            if (
                ! wp?.element?.createRoot ||
                ! wp?.element?.createElement ||
                ! wp?.hooks?.applyFilters ||
                ! wp?.data?.select
            ) {
                return false;
            }
            if ( ! wp.data.select( 'rank-math' )?.isLoaded?.() ) {
                return false;
            }
            const App = wp.hooks.applyFilters( 'rank_math_app', {} );
            if ( typeof App !== 'function' ) {
                return false;
            }
            try {
                wp.element
                    .createRoot( wrapper )
                    .render( wp.element.createElement( App ) );
                mountedRef.current = true;
                return true;
            } catch ( e ) {
                // eslint-disable-next-line no-console
                console.error( '[Dokan RankMath] manual mount failed:', e );
                return false;
            }
        };

        // Rank Math's data collector wires itself to legacy form ids. On
        // the new editor we render hidden mirrors of those ids and rebind
        // the collector to them so the SERP preview and SEO analysis pick
        // up the live product title, slug, content, and short description.
        //
        // The rebind alone is not enough: the analyzer caches the values it
        // read at its first run (when the React inputs were still empty or
        // not yet rendered), so we also have to push the live values into
        // the `rank-math` data store and ask the analyzer to refresh. This
        // is what turns "URL unavailable" / "Add a number to your title" /
        // "Add short paragraphs" into the green checks the legacy editor
        // shows.
        const rebind = () => {
            const rm = ( window as any ).rankMathEditor;
            const $ = ( window as any ).jQuery;
            const wp = ( window as any ).wp;
            if ( ! rm?.assessor?.dataCollector || ! $ ) {
                return false;
            }

            const title = data?.name ?? '';
            const slug = data?.slug ?? '';
            const content = data?.description ?? '';
            const description = data?.short_description ?? '';

            // Re-point the element references and fire events so any
            // assessor listening for change picks up the new values.
            const titleEl = $( '#title' );
            const slugEl = $( '#post_name' );
            const contentEl = $( '#post_content' );
            const descriptionEl = $( '#post_excerpt' );
            rm.assessor.dataCollector.elemTitle = titleEl;
            rm.assessor.dataCollector.elemSlug = slugEl;
            rm.assessor.dataCollector.elemContent = contentEl;
            rm.assessor.dataCollector.elemDescription = descriptionEl;

            // Push live values into the Rank Math data store so the SERP
            // preview, analysis, and snippet editor read the same data the
            // legacy editor would have at first paint.
            const dispatch = wp?.data?.dispatch?.( 'rank-math' );
            if ( dispatch ) {
                try {
                    dispatch.updateAppData?.( 'title', title );
                    dispatch.updateAppData?.( 'slug', slug );
                    dispatch.updateAppData?.( 'content', content );
                    dispatch.updateAppData?.( 'excerpt', description );
                    dispatch.refreshResults?.();
                } catch ( e ) {
                    // Older Rank Math builds may expose only some of these
                    // actions — fall through to the assessor refresh below.
                }
            }

            // Fall back to the classic assessor refresh if no data store is
            // present (older builds) or if dispatch threw.
            if ( typeof rm.refresh === 'function' ) {
                try {
                    rm.refresh();
                } catch ( e ) {}
            }

            return true;
        };

        let mountDone = tryMount();
        let rebindDone = rebind();
        if ( mountDone && rebindDone ) {
            return;
        }

        let attempts = 0;
        const interval = setInterval( () => {
            attempts += 1;
            if ( ! mountDone ) {
                mountDone = tryMount();
            }
            if ( ! rebindDone ) {
                rebindDone = rebind();
            }
            if ( ( mountDone && rebindDone ) || attempts >= 60 ) {
                clearInterval( interval );
            }
        }, 250 );

        return () => clearInterval( interval );
    }, [ isNew, productId, needsSync ] );

    if ( isNew ) {
        return (
            <div className="dokan-rank-math-mount dokan-rank-math-mount--new">
                <p>
                    { __(
                        'Save the product first to manage Rank Math SEO.',
                        'dokan'
                    ) }
                </p>
            </div>
        );
    }

    if ( needsSync ) {
        return (
            <div className="dokan-rank-math-mount dokan-rank-math-mount--loading">
                <p>{ __( 'Loading SEO panel…', 'dokan' ) }</p>
            </div>
        );
    }

    return (
        <div className="dokan-rank-math-mount">
            <input
                type="hidden"
                id="post_name"
                value={ data?.slug ?? '' }
                readOnly
            />
            <input
                type="hidden"
                id="title"
                value={ data?.name ?? '' }
                readOnly
            />
            <input
                type="hidden"
                id="post_content"
                value={ data?.description ?? '' }
                readOnly
            />
            <input
                type="hidden"
                id="post_excerpt"
                value={ data?.short_description ?? '' }
                readOnly
            />
            <div id="rank-math-metabox-wrapper" />
        </div>
    );
};

export default RankMathMount;
